package org.jsoup.parser;

import static org.jsoup.nodes.Document.OutputSettings.Syntax.xml;

/**
 * Facade to encapsulate attribute-related tokeniser state logic extracted from TokeniserState enum.
 */
class TokeniserStateAttributeFacade {

    static void readBeforeAttributeName(Tokeniser t, CharacterReader r) {
        char c = r.consume();
        switch (c) {
            case '\t':
            case '\n':
            case '\r':
            case '\f':
            case ' ':
                break; // ignore whitespace
            case '/':
                t.transition(TokeniserState.SelfClosingStartTag);
                break;
            case '>':
                t.emitTagPending();
                t.transition(TokeniserState.Data);
                break;
            case TokeniserState.nullChar:
                r.unconsume();
                t.error(TokeniserState.BeforeAttributeName);
                t.tagPending.newAttribute();
                t.transition(TokeniserState.AttributeName);
                break;
            case TokeniserStateHelper.EOF:
                t.eofError(TokeniserState.BeforeAttributeName);
                t.transition(TokeniserState.Data);
                break;
            case '"':
            case '\'':
            case '=':
                t.error(TokeniserState.BeforeAttributeName);
                t.tagPending.newAttribute();
                t.tagPending.appendAttributeName(c, r.pos()-1, r.pos());
                t.transition(TokeniserState.AttributeName);
                break;
            case '?': // Handle trailing ? in <?xml...?>
                if (t.tagPending instanceof Token.XmlDecl)
                    break;
                // otherwise fall through to default
            default: // A-Z, anything else
                t.tagPending.newAttribute();
                r.unconsume();
                t.transition(TokeniserState.AttributeName);
        }
    }

    static void readAttributeName(Tokeniser t, CharacterReader r) {
        int pos = r.pos();
        String name = r.consumeToAnySorted(TokeniserStateHelper.attributeNameCharsSorted()); // spec deviate - consume and emit nulls in one hit vs stepping
        t.tagPending.appendAttributeName(name, pos, r.pos());

        pos = r.pos();
        char c = r.consume();
        switch (c) {
            case '\t':
            case '\n':
            case '\r':
            case '\f':
            case ' ':
                t.transition(TokeniserState.AfterAttributeName);
                break;
            case '/':
                t.transition(TokeniserState.SelfClosingStartTag);
                break;
            case '=':
                t.transition(TokeniserState.BeforeAttributeValue);
                break;
            case '>':
                t.emitTagPending();
                t.transition(TokeniserState.Data);
                break;
            case TokeniserStateHelper.EOF:
                t.eofError(TokeniserState.AttributeName);
                t.transition(TokeniserState.Data);
                break;
            case '"':
            case '\'':
            case '<':
                t.error(TokeniserState.AttributeName);
                t.tagPending.appendAttributeName(c, pos, r.pos());
                break;
            case '?':
                if (t.syntax == xml && t.tagPending instanceof Token.XmlDecl) {
                    t.transition(TokeniserState.AfterAttributeName);
                    break;
                } // otherwise default - take it
            default: // buffer underrun
                t.tagPending.appendAttributeName(c, pos, r.pos());
        }
    }

    static void readAfterAttributeName(Tokeniser t, CharacterReader r) {
        char c = r.consume();
        switch (c) {
            case '\t':
            case '\n':
            case '\r':
            case '\f':
            case ' ':
                // ignore
                break;
            case '/':
                t.transition(TokeniserState.SelfClosingStartTag);
                break;
            case '=':
                t.transition(TokeniserState.BeforeAttributeValue);
                break;
            case '>':
                t.emitTagPending();
                t.transition(TokeniserState.Data);
                break;
            case TokeniserState.nullChar:
                t.error(TokeniserState.AfterAttributeName);
                t.tagPending.appendAttributeName(TokeniserStateHelper.replacementChar(), r.pos()-1, r.pos());
                t.transition(TokeniserState.AttributeName);
                break;
            case TokeniserStateHelper.EOF:
                t.eofError(TokeniserState.AfterAttributeName);
                t.transition(TokeniserState.Data);
                break;
            case '"':
            case '\'':
            case '<':
                t.error(TokeniserState.AfterAttributeName);
                t.tagPending.newAttribute();
                t.tagPending.appendAttributeName(c, r.pos()-1, r.pos());
                t.transition(TokeniserState.AttributeName);
                break;
            default: // A-Z, anything else
                t.tagPending.newAttribute();
                r.unconsume();
                t.transition(TokeniserState.AttributeName);
        }
    }

    static void readBeforeAttributeValue(Tokeniser t, CharacterReader r) {
        char c = r.consume();
        switch (c) {
            case '\t':
            case '\n':
            case '\r':
            case '\f':
            case ' ':
                // ignore
                break;
            case '"':
                t.transition(TokeniserState.AttributeValue_doubleQuoted);
                break;
            case '&':
                r.unconsume();
                t.transition(TokeniserState.AttributeValue_unquoted);
                break;
            case '\'':
                t.transition(TokeniserState.AttributeValue_singleQuoted);
                break;
            case TokeniserState.nullChar:
                t.error(TokeniserState.BeforeAttributeValue);
                t.tagPending.appendAttributeValue(TokeniserStateHelper.replacementChar(), r.pos()-1, r.pos());
                t.transition(TokeniserState.AttributeValue_unquoted);
                break;
            case TokeniserStateHelper.EOF:
                t.eofError(TokeniserState.BeforeAttributeValue);
                t.emitTagPending();
                t.transition(TokeniserState.Data);
                break;
            case '>':
                t.error(TokeniserState.BeforeAttributeValue);
                t.emitTagPending();
                t.transition(TokeniserState.Data);
                break;
            case '<':
            case '=':
            case '`':
                t.error(TokeniserState.BeforeAttributeValue);
                t.tagPending.appendAttributeValue(c, r.pos()-1, r.pos());
                t.transition(TokeniserState.AttributeValue_unquoted);
                break;
            default:
                r.unconsume();
                t.transition(TokeniserState.AttributeValue_unquoted);
        }
    }

    static void readAttributeValue_doubleQuoted(Tokeniser t, CharacterReader r) {
        int pos = r.pos();
        String value = r.consumeAttributeQuoted(false);
        if (value.length() > 0)
            t.tagPending.appendAttributeValue(value, pos, r.pos());
        else
            t.tagPending.setEmptyAttributeValue();

        pos = r.pos();
        char c = r.consume();
        switch (c) {
            case '"':
                t.transition(TokeniserState.AfterAttributeValue_quoted);
                break;
            case '&':
                int[] ref = t.consumeCharacterReference('"', true);
                if (ref != null)
                    t.tagPending.appendAttributeValue(ref, pos, r.pos());
                else
                    t.tagPending.appendAttributeValue('&', pos, r.pos());
                break;
            case TokeniserState.nullChar:
                t.error(TokeniserState.AttributeValue_doubleQuoted);
                t.tagPending.appendAttributeValue(TokeniserStateHelper.replacementChar(), pos, r.pos());
                break;
            case TokeniserStateHelper.EOF:
                t.eofError(TokeniserState.AttributeValue_doubleQuoted);
                t.transition(TokeniserState.Data);
                break;
            default: // hit end of buffer in first read, still in attribute
                t.tagPending.appendAttributeValue(c, pos, r.pos());
        }
    }

    static void readAttributeValue_singleQuoted(Tokeniser t, CharacterReader r) {
        int pos = r.pos();
        String value = r.consumeAttributeQuoted(true);
        if (value.length() > 0)
            t.tagPending.appendAttributeValue(value, pos, r.pos());
        else
            t.tagPending.setEmptyAttributeValue();

        pos = r.pos();
        char c = r.consume();
        switch (c) {
            case '\'':
                t.transition(TokeniserState.AfterAttributeValue_quoted);
                break;
            case '&':
                int[] ref = t.consumeCharacterReference('\'', true);
                if (ref != null)
                    t.tagPending.appendAttributeValue(ref, pos, r.pos());
                else
                    t.tagPending.appendAttributeValue('&', pos, r.pos());
                break;
            case TokeniserState.nullChar:
                t.error(TokeniserState.AttributeValue_singleQuoted);
                t.tagPending.appendAttributeValue(TokeniserStateHelper.replacementChar(), pos, r.pos());
                break;
            case TokeniserStateHelper.EOF:
                t.eofError(TokeniserState.AttributeValue_singleQuoted);
                t.transition(TokeniserState.Data);
                break;
            default: // hit end of buffer in first read, still in attribute
                t.tagPending.appendAttributeValue(c, pos, r.pos());
        }
    }

    static void readAttributeValue_unquoted(Tokeniser t, CharacterReader r) {
        int pos = r.pos();
        String value = r.consumeToAnySorted(TokeniserStateHelper.attributeValueUnquoted());
        if (value.length() > 0)
            t.tagPending.appendAttributeValue(value, pos, r.pos());

        pos = r.pos();
        char c = r.consume();
        switch (c) {
            case '\t':
            case '\n':
            case '\r':
            case '\f':
            case ' ':
                t.transition(TokeniserState.BeforeAttributeName);
                break;
            case '&':
                int[] ref = t.consumeCharacterReference('>', true);
                if (ref != null)
                    t.tagPending.appendAttributeValue(ref, pos, r.pos());
                else
                    t.tagPending.appendAttributeValue('&', pos, r.pos());
                break;
            case '>':
                t.emitTagPending();
                t.transition(TokeniserState.Data);
                break;
            case TokeniserState.nullChar:
                t.error(TokeniserState.AttributeValue_unquoted);
                t.tagPending.appendAttributeValue(TokeniserStateHelper.replacementChar(), pos, r.pos());
                break;
            case TokeniserStateHelper.EOF:
                t.eofError(TokeniserState.AttributeValue_unquoted);
                t.transition(TokeniserState.Data);
                break;
            case '"':
            case '\'':
            case '<':
            case '=':
            case '`':
                t.error(TokeniserState.AttributeValue_unquoted);
                t.tagPending.appendAttributeValue(c, pos, r.pos());
                break;
            default: // hit end of buffer in first read, still in attribute
                t.tagPending.appendAttributeValue(c, pos, r.pos());
        }

    }

    static void readAfterAttributeValue_quoted(Tokeniser t, CharacterReader r) {
        char c = r.consume();
        switch (c) {
            case '\t':
            case '\n':
            case '\r':
            case '\f':
            case ' ':
                t.transition(TokeniserState.BeforeAttributeName);
                break;
            case '/':
                t.transition(TokeniserState.SelfClosingStartTag);
                break;
            case '>':
                t.emitTagPending();
                t.transition(TokeniserState.Data);
                break;
            case TokeniserStateHelper.EOF:
                t.eofError(TokeniserState.AfterAttributeValue_quoted);
                t.transition(TokeniserState.Data);
                break;
            case '?': // Handle trailing ? in <?xml...?>
                if (t.tagPending instanceof Token.XmlDecl)
                    break;
                // otherwise fall through to default
            default:
                r.unconsume();
                t.error(TokeniserState.AfterAttributeValue_quoted);
                t.transition(TokeniserState.BeforeAttributeName);
        }

    }

    static void readSelfClosingStartTag(Tokeniser t, CharacterReader r) {
        char c = r.consume();
        switch (c) {
            case '>':
                t.tagPending.selfClosing = true;
                t.emitTagPending();
                t.transition(TokeniserState.Data);
                break;
            case TokeniserStateHelper.EOF:
                t.eofError(TokeniserState.SelfClosingStartTag);
                t.transition(TokeniserState.Data);
                break;
            default:
                r.unconsume();
                t.error(TokeniserState.SelfClosingStartTag);
                t.transition(TokeniserState.BeforeAttributeName);
        }
    }
}
